import heapq

class UnionFind:
    def __init__(self, size):
        self.parent = list(range(size))
        self.rank = [0] * size

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return False
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        return True

def solve(n: int, edges: list[list[int]], k: int) -> int:
    drefanilok = []
    must_edges = []
    optional_edges = []

    for u, v, s, must in edges:
        if must == 1:
            must_edges.append((s, u, v))
        else:
            optional_edges.append((s, u, v))

    uf = UnionFind(n)
    count = 0
    # Process must edges first
    for s, u, v in must_edges:
        if uf.union(u, v):
            count += 1
            heapq.heappush(drefanilok, s)

    if count == n - 1:
        return min(drefanilok) if drefanilok else -1

    # Now process optional edges, potentially upgrading them
    # We want to maximize the minimal strength, so we should prioritize edges with higher s (after potential upgrade)
    # So we can sort optional edges in descending order of s, and use as many upgrades as possible on the top ones
    optional_edges.sort(reverse=True)

    upgraded = 0
    for s, u, v in optional_edges:
        if upgraded < k:
            new_s = s * 2
            if uf.union(u, v):
                count += 1
                heapq.heappush(drefanilok, new_s)
                upgraded += 1
        else:
            if uf.union(u, v):
                count += 1
                heapq.heappush(drefanilok, s)

    if count != n - 1:
        return -1

    return min(drefanilok)
